import "fmt"

func solve(nums []int64, queries [][]int64) []int64 {
	// Precompute popcount-depth for each number in nums
	var getPopcountDepth func(x int64) int
	getPopcountDepth = func(x int64) int {
		depth := 0
		for x > 0 {
			x = popcount(x)
			depth++
		}
		return depth
	}

	// Precompute popcount-depth for all numbers in nums
	depthList := make([]int, len(nums))
	for i := 0; i < len(nums); i++ {
		depthList[i] = getPopcountDepth(nums[i])
	}

	// Initialize depth_freq array for depths 0 to 5
	depthFreq := make([]int, 6)
	for _, d := range depthList {
		depthFreq[d]++
	}

	// Function to update the frequency array
	updateFreq := func(idx int, oldVal, newVal int) {
		depthFreq[oldVal]--
		depthFreq[newVal]++
	}

	// Function to answer a query of type [1, l, r, k]
	answerQuery := func(l, r, k int) int {
		// Since the depth can be up to 5, we can directly access the count
		return depthFreq[k]
	}

	// Process each query
	answer := make([]int64, len(queries))
	for i, query := range queries {
		if query[0] == 1 {
			l, r, k := int(query[1]), int(query[2]), int(query[3])
			answer[i] = int64(answerQuery(l, r, k))
		} else {
			idx, val := int(query[1]), int(query[2])
			oldVal := nums[idx]
			newVal := int64(val)
			// Update the nums array
			nums[idx] = newVal
			// Update the depthList
			oldDepth := depthList[idx]
			newDepth := getPopcountDepth(newVal)
			updateFreq(idx, oldDepth, newDepth)
			depthList[idx] = newDepth
		}
	}

	return answer
}

// Helper function to count the number of 1s in the binary representation of a number
func popcount(x int64) int {
	count := 0
	for x > 0 {
		count += int(x & 1)
		x >>= 1
	}
	return count
}
